def perceive(data):
    status = int(data.get("status", 200))
    remaining = int(data.get("remaining", 0))
    retry_after = int(data.get("retry_after", 0))
    return {
        "tokens": max(0, remaining),
        "cooldown": max(0, retry_after),
        "last_status": "429" if status == 429 else "ok",
    }
